class LocalRAGIndex:
    def __init__(self, chunks):
        self.chunks = chunks
        self.vectors = [self._embed(c) for c in chunks]

    def _embed(self, text):
        words = text.lower().split()
        if not words:
            return {}
        vec = {}
        for w in words:
            vec[w] = vec.get(w, 0) + 1
        return {w: c / len(words) for w, c in vec.items()}

    def _score(self, q, d):
        return sum(q[w] * d.get(w, 0) for w in q)

    def search(self, query, top_k=3):
        q = self._embed(query)
        scored = [
            (self._score(q, v), i, c)
            for i, (c, v) in enumerate(zip(self.chunks, self.vectors))
        ]
        scored.sort(key=lambda t: (-t[0], t[1]))
        return [{"chunk": c, "score": s} for s, _, c in scored[:top_k]]

